namespace BgControls.Windows.Controls.DragDrop.NativeWrappers;/// <summary>/// 原生窗口样式包装类，用于修改窗口的扩展样式./// </summary>internal static class NativeWindowStyleWrapper{    /// <summary>    /// 原生方法定义类.    /// </summary>    private static class NativeMethods    {        /// <summary>        /// 获取指定窗口的信息.        /// </summary>        /// <param name="handle">窗口句柄.</param>        /// <param name="index">要获取的值的偏移量.</param>        /// <returns>返回窗口的信息值. </returns>        [DllImport("user32.dll", CharSet = CharSet.Auto)]        public static extern int GetWindowLong(IntPtr handle, int index);        /// <summary>        /// 改变指定窗口的属性.        /// </summary>        /// <param name="handle">窗口句柄.</param>        /// <param name="index">要设置的值的偏移量.</param>        /// <param name="newValue">新值.</param>        /// <returns>返回之前的值. </returns>        [DllImport("user32.dll", CharSet = CharSet.Auto)]        public static extern int SetWindowLong(IntPtr handle, int index, int newValue);    }    /// <summary>    /// 窗口扩展样式索引常量.    /// </summary>    public const int GwlExStyle = -20;    /// <summary>    /// 分层窗口样式常量.    /// </summary>    public const int WsExLayered = 524288;    /// <summary>    /// 透明窗口样式常量.    /// </summary>    public const int WsExTransparent = 32;    /// <summary>    /// 设置窗口为透明穿透样式.    /// </summary>    /// <param name="dragdropWindow">目标窗口对象.</param>    public static void SetTransparentStyle(Window dragdropWindow)    {        // 参数检查.        ArgumentNullException.ThrowIfNull(dragdropWindow, nameof(dragdropWindow));        // 获取窗口对应的句柄源.        PresentationSource presentationSource = PresentationSource.FromVisual(dragdropWindow);        IntPtr windowHandle = ((HwndSource)presentationSource).Handle;        // 获取当前的扩展样式并叠加分层与透明标志.        int currentExStyle = NativeMethods.GetWindowLong(windowHandle, NativeWindowStyleWrapper.GwlExStyle);        int targetExStyle = currentExStyle | NativeWindowStyleWrapper.WsExLayered | NativeWindowStyleWrapper.WsExTransparent;        // 设置新的窗口样式.        if (NativeMethods.SetWindowLong(windowHandle, NativeWindowStyleWrapper.GwlExStyle, targetExStyle) == 0 && Marshal.GetLastWin32Error() != 0)        {            throw new Win32Exception("Could not set window transparent style.");        }    }}